const incoming = $input.first().json;
const body = incoming.body || incoming;

let phone = '';
if (body.payload && body.payload.from) {
  phone = body.payload.from;
} else if (body.from) {
  phone = body.from;
}
phone = phone.replace('@c.us', '').replace('@s.whatsapp.net', '');

let message = '';
if (body.payload && body.payload.body) {
  message = body.payload.body;
} else if (body.body) {
  message = body.body;
} else if (body.text) {
  message = body.text;
}

let patientName = 'عميل';
if (body.payload && body.payload.notifyName) {
  patientName = body.payload.notifyName;
} else if (body.notifyName) {
  patientName = body.notifyName;
} else if (body.pushName) {
  patientName = body.pushName;
}

const chatId = phone + '@c.us';

let intent = 'inquiry';
if (/حجز|موعد|احجز|booking|appointment|ميعاد/i.test(message)) {
  intent = 'booking';
}

return {
  json: {
    phone: phone,
    message: message,
    patientName: patientName,
    chatId: chatId,
    intent: intent,
    timestamp: new Date().toISOString()
  }
};

const memoryData = $input.first().json;
const parsedMessage = $('2. Message Parser').first().json;

let memoryContext = '';
if (Array.isArray(memoryData) && memoryData.length > 0) {
  memoryContext = memoryData.map((m) => {
    return `• ${m.fact || m.summary || 'N/A'}`;
  }).join('\n');
} else {
  memoryContext = 'لا توجد سجلات سابقة لهذا المريض.';
}

const sessionContext = {
  phone: parsedMessage.phone,
  patientName: parsedMessage.patientName,
  currentMessage: parsedMessage.message,
  intent: parsedMessage.intent,
  chatId: parsedMessage.chatId,
  timestamp: parsedMessage.timestamp,
  memoryContext: memoryContext,
  memoryCount: Array.isArray(memoryData) ? memoryData.length : 0,
  sessionId: `session_${parsedMessage.phone}_${Date.now()}`
};

return { json: sessionContext };

